You can use the == operator with standard strings:

Rcpp::cppFunction('
void test(std::string x) {
  if (x == "flower")
    Rcout << "flower" << std::endl;
  else if (x == "tree")
    Rcout << "tree" << std::endl;
  else
    Rcout << "string " << x << " not found" << std::endl;
}
')

test("flower")
#> flower
test("tree")
#> tree
test("other")
#> string other not found


